3	export type Resolvable<T> = MaybePromiseLike<T> | (() => MaybePromiseLike<T>);
4	
5	/**
6	 * Resolves a value that could be a raw value, a Promise, a function returning a value,
7	 * or a function returning a Promise.
8	 */
9	export async function resolve<T>(value: Resolvable<T>): Promise<T> {
10	  // If it's a function, call it to get the value/promise
11	  if (typeof value === 'function') {
12	    value = (value as Function)();
13	  }
14	
15	  // Otherwise just resolve whatever we got (value or promise)
16	  return Promise.resolve(value as T);
17	}
