1	/**
2	 * Creates a Promise that resolves after a specified delay
3	 * @param delayInMs - The delay duration in milliseconds. If null or undefined, resolves immediately.
4	 * @param signal - Optional AbortSignal to cancel the delay
5	 * @returns A Promise that resolves after the specified delay
6	 * @throws {DOMException} When the signal is aborted
7	 */
8	export async function delay(
9	  delayInMs?: number | null,
10	  options?: {
11	    abortSignal?: AbortSignal;
12	  },
13	): Promise<void> {
14	  if (delayInMs == null) {
15	    return Promise.resolve();
16	  }
17	
18	  const signal = options?.abortSignal;
19	
20	  return new Promise<void>((resolve, reject) => {
21	    if (signal?.aborted) {
22	      reject(createAbortError());
23	      return;
24	    }
25	
26	    const timeoutId = setTimeout(() => {
27	      cleanup();
28	      resolve();
29	    }, delayInMs);
30	
31	    const cleanup = () => {
32	      clearTimeout(timeoutId);
33	      signal?.removeEventListener('abort', onAbort);
34	    };
35	
36	    const onAbort = () => {
37	      cleanup();
38	      reject(createAbortError());
39	    };
40	
41	    signal?.addEventListener('abort', onAbort);
42	  });
43	}
44	
45	function createAbortError(): DOMException {
46	  return new DOMException('Delay was aborted', 'AbortError');
47	}
